  ('medical-tech-moex-21050', 'medical-tech', 'medical-tech-moex-093-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '下列何者常用來進行病毒特異性感染？ 病毒定量  病毒干擾試驗  免疫螢光染色  血球吸附試驗', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:17+00:00", "source_pdf_sha1": "7e17c29d4088", "answer_pdf_sha1": "05e1b2825517", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 57, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-21051', 'medical-tech', 'medical-tech-moex-093-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', 'ICAM-1（intercellular adhesion molecule-1）為何種病毒之接受器？ 腸病毒（Enterovirus）  鼻病毒（Rhinovirus）  EB病毒（EBV）  單純 疹病毒（HSV）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:17+00:00", "source_pdf_sha1": "7e17c29d4088", "answer_pdf_sha1": "05e1b2825517", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 58, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-21052', 'medical-tech', 'medical-tech-moex-093-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '下列何種病毒之抗體測定是目前捐血時必須檢驗的項目？ A型肝炎病毒（Hepatitis A virus）  C型肝炎病毒（Hepatitis C virus） E型肝炎病毒（Hepatitis E virus）  G型肝炎病毒（Hepatitis G virus）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:17+00:00", "source_pdf_sha1": "7e17c29d4088", "answer_pdf_sha1": "05e1b2825517", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 59, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-21053', 'medical-tech', 'medical-tech-moex-093-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '下列何種病毒在細胞核中進行核酸複製？ 腸病毒（Enterovirus）    副流行性感冒病毒（Parainfluenza virus） 痘病毒（Poxvirus）    流行性感冒病毒（Influenza virus）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:17+00:00", "source_pdf_sha1": "7e17c29d4088", "answer_pdf_sha1": "05e1b2825517", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 60, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-21054', 'medical-tech', 'medical-tech-moex-093-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', 'E型肝炎病毒（Hepatitis E virus）屬於那一病毒科？ 杯狀病毒科（Caliciviridae）  黃病毒科（Flaviviridae） 小RNA病毒科（Picornaviridae）  肝病毒科（Hepadnaviridae）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:17+00:00", "source_pdf_sha1": "7e17c29d4088", "answer_pdf_sha1": "05e1b2825517", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 61, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-21055', 'medical-tech', 'medical-tech-moex-093-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '下列關於漢他病毒（Hantavirus）之敘述，何者錯誤？ 屬於布尼亞病毒科（Bunyaviridae）  其基因結構主要由三段單鏈RNA組成 其傳播需要蚊蟲做媒介    漢他病毒腎症候群（HFRS）主要分布於東亞地區', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:17+00:00", "source_pdf_sha1": "7e17c29d4088", "answer_pdf_sha1": "05e1b2825517", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "105", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 62, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
